sql:
SELECT program_name, ACOS(points_required) 
FROM loyalty_programs 
WHERE program_id = 'your_program_id';

SELECT DISTINCT manager_id
FROM stores
WHERE store_id IN (SELECT store_id FROM customer_loyalty);

external_knowledge:
- 'captains steering the ship' refers to managers with 'Manager' in their title;
- 'since the dawn of the new millennium up to the early part of the 2020s' refers to managers hired between January 1, 2010, and January 1, 2023;
- 'average salary above the golden threshold of fifty thousand dollars' refers to managers whose average salary is more than $50,000.

sql:
SELECT first_name, last_name, salary
FROM managers
WHERE salary > (
    SELECT AVG(salary) 
    FROM managers
) AND strftime('%Y-%m', hire_date) < strftime('%Y-%m', 'now');

SELECT first_name, store_id 
FROM managers 
WHERE manager_id > 5;
